#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Node{
    int l,r,id;
}seg[N];

int n,m,a[N],ls[N],sum[N],cnt[N],ans[N],c[N];
map<int,int> mp;

int cal(int x){
    return (x-1)/450+1;
}

bool cmp(Node x,Node y){
    if(c[x.l]==c[y.l])
        return x.r<y.r;
    return c[x.l]<c[y.l];
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        ls[i]=a[i];
        c[i]=cal(i);
    }
    sort(ls+1,ls+n+1);
    int len=unique(ls+1,ls+n+1)-ls-1;
    for(int i=1;i<=len;i++)
        mp[ls[i]]=i;
    for(int i=1;i<=n;i++)
        a[i]=mp[a[i]];
    for(int i=1;i<=m;i++){
        scanf("%d%d",&seg[i].l,&seg[i].r);
        seg[i].id=i;
    }
    sort(seg+1,seg+m+1,cmp);
    int l=1,r=0,res=0;
    len=450; 
    for(int i=1;i<=m;i++){
        if(c[seg[i].l]==c[seg[i].r]){
            int mx=0;
            for(int j=seg[i].l;j<=seg[i].r;j++){
                cnt[a[j]]++;
                if(cnt[a[j]]>cnt[mx])
                    mx=a[j];
            }
            ans[seg[i].id]=cnt[mx];
            for(int j=seg[i].l;j<=seg[i].r;j++)
                cnt[a[j]]--;
            continue;
        }
        if(c[seg[i].l]!=c[l-1] || i==1){
            r=c[seg[i].l]*450,l=r+1;
            memset(sum,0,sizeof(sum));
            res=0;
        }
        while(r<seg[i].r){
            r++;
            sum[a[r]]++;
            if(sum[a[r]]>sum[res])
                res=a[r];
        }
        int lst=res;
        while(l>seg[i].l){
            l--;
            sum[a[l]]++;
            if(sum[a[l]]>sum[res])
                res=a[l];
        }
        ans[seg[i].id]=sum[res];
        res=lst;
        while(l<=450*c[seg[i].l]){
            sum[a[l]]--;
            l++;
        }
    }
    for(int i=1;i<=m;i++)
        printf("-%d\n",ans[i]);
    return 0;
}
